            )
        case 4: return .BadPassphrase
        case 5: return .Frost(
            msg: try FfiConverterString.read(from: &buf)
            )
        case 6: return .Format(
            msg: try FfiConverterString.read(from: &buf)
            )
        case 7: return .Wiped
        case 8: return .NoSession
        case 9: return .Unexpected
        case 10: return .Rng(
            msg: try FfiConverterString.read(from: &buf)
            )

         default: throw UniffiInternalError.unexpectedEnumCase
        }
