private enum InitializationResult {
    case ok
    case contractVersionMismatch
    case apiChecksumMismatch
}
// Use a global variable to perform the versioning checks. Swift ensures that
// the code inside is only computed once.
private let initializationResult: InitializationResult = {
    // Get the bindings contract version from our ComponentInterface
    let bindings_contract_version = 30
    // Get the scaffolding contract version by calling the into the dylib
    let scaffolding_contract_version = ffi_steward_ffi_uniffi_contract_version()
    if bindings_contract_version != scaffolding_contract_version {
        return InitializationResult.contractVersionMismatch
    }
    if (uniffi_steward_ffi_checksum_func_open_guardian() != 50376) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_steward_ffi_checksum_func_generate_heartbeat_key() != 35325) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_steward_ffi_checksum_func_heartbeat_pubkey() != 38735) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_steward_ffi_checksum_func_is_lapsed() != 18647) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_steward_ffi_checksum_func_sign_heartbeat() != 30508) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_steward_ffi_checksum_func_verify_heartbeat() != 53228) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_steward_ffi_checksum_func_split_authority() != 35616) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_steward_ffi_checksum_func_seal_share() != 59710) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_steward_ffi_checksum_func_aggregate_signature() != 63799) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_steward_ffi_checksum_func_build_signing_package() != 30401) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_steward_ffi_checksum_func_random_randomizer_hex() != 61912) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_steward_ffi_checksum_func_randomized_verifying_key_hex() != 32116) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_steward_ffi_checksum_func_verify_aggregate() != 16335) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_steward_ffi_checksum_method_guardian_adjourn() != 16491) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_steward_ffi_checksum_method_guardian_handle_relay_message() != 36894) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_steward_ffi_checksum_method_guardian_identifier() != 42066) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_steward_ffi_checksum_method_guardian_pending_count() != 13566) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_steward_ffi_checksum_method_guardian_round1() != 19253) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_steward_ffi_checksum_method_guardian_round2() != 51063) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_steward_ffi_checksum_method_guardian_wipe() != 48537) {
        return InitializationResult.apiChecksumMismatch
